using namespace std;

long long solve(long long m, long long n, vector<vector<long long>> waitCost) {
    if (m == 0 || n == 0) return 0;

    vector<vector<vector<long long>>> dist(m, vector<vector<long long>>(n, vector<long long>(2, LLONG_MAX)));
    priority_queue<tuple<long long, long long, long long, long long>, vector<tuple<long long, long long, long long, long long>>, greater<>> pq;

    // Initial state: (time % 2, cost, i, j)
    dist[0][0][1] = (0 + 1) * (0 + 1); // first step is odd (1)
    pq.emplace(dist[0][0][1], 0, 0, 1);

    int dirs[2][2] = {{0, 1}, {1, 0}}; // right and down

    while (!pq.empty()) {
        auto [current_cost, i, j, time_parity] = pq.top();
        pq.pop();

        if (i == m - 1 && j == n - 1) {
            return current_cost;
        }

        if (time_parity == 1) { // odd time: move
            for (auto &dir : dirs) {
                int ni = i + dir[0];
                int nj = j + dir[1];
                if (ni < m && nj < n) {
                    long long new_cost = current_cost + (ni + 1) * (nj + 1);
                    if (new_cost < dist[ni][nj][0]) {
                        dist[ni][nj][0] = new_cost;
                        pq.emplace(new_cost, ni, nj, 0);
                    }
                }
            }
        } else { // even time: wait
            long long new_cost = current_cost + waitCost[i][j];
            if (new_cost < dist[i][j][1]) {
                dist[i][j][1] = new_cost;
                pq.emplace(new_cost, i, j, 1);
            }
        }
    }

    return -1; // unreachable
}

